169	    if args[1].rank() != 0 {
170	        return Err(RuntimeError::InvalidArgument {
171	            func: name.into(),
172	            reason: format!("axis must be scalar, got rank {}", args[1].rank()),
173	        });
174	    }
175	    let a = &args[0];
176	    let axis = args[1].data()[0] as usize;
177	    let dims = a.shape().dims().to_vec();
178	    if axis >= dims.len() {
179	        return Err(RuntimeError::InvalidArgument {
180	            func: name.into(),
181	            reason: format!("axis {axis} out of range for rank {}", dims.len()),
182	        });
183	    }
184	
185	    // Strides for the input shape.
186	    let mut strides = vec![1usize; dims.len()];
187	    for i in (0..dims.len().saturating_sub(1)).rev() {
188	        strides[i] = strides[i + 1] * dims[i + 1];
189	    }
190	    let axis_size = dims[axis];
191	    let axis_stride = strides[axis];
192	
193	    // Group index: flat index with the `axis` coordinate removed.
194	    let mut group_dims = dims.clone();
195	    group_dims.remove(axis);
196	    let group_count: usize = group_dims.iter().product::<usize>().max(1);
197	
198	    // First pass: per-group max for numerical stability.
199	    let mut maxv = vec![f64::NEG_INFINITY; group_count];
200	    for flat in 0..a.elem_count() {
201	        let g = if axis_stride > 1 {
202	            let outer = flat / (axis_size * axis_stride);
203	            let inner = flat % axis_stride;
204	            outer * axis_stride + inner
205	        } else {
206	            flat / axis_size
207	        };
208	        let v = a.data()[flat];
209	        if v > maxv[g] {
210	            maxv[g] = v;
211	        }
212	    }
213	
214	    // Second pass: exponentiate shifted logits and accumulate per-group sums.
215	    let mut out = vec![0.0f64; a.elem_count()];
216	    let mut sums = vec![0.0f64; group_count];
217	    for (flat, slot) in out.iter_mut().enumerate() {
218	        let g = if axis_stride > 1 {
219	            let outer = flat / (axis_size * axis_stride);
220	            let inner = flat % axis_stride;
221	            outer * axis_stride + inner
222	        } else {
223	            flat / axis_size
224	        };
225	        let e = (a.data()[flat] - maxv[g]).exp();
226	        *slot = e;
227	        sums[g] += e;
228	    }
229	
230	    // Third pass: normalize.
231	    for (flat, slot) in out.iter_mut().enumerate() {
232	        let g = if axis_stride > 1 {
233	            let outer = flat / (axis_size * axis_stride);
234	            let inner = flat % axis_stride;
235	            outer * axis_stride + inner
236	        } else {
237	            flat / axis_size
238	        };
239	        *slot /= sums[g];
240	    }
