114	fn sample_high_temperature_distribution_matches_softmax() {
115	    // At very high temperature the distribution flattens toward
116	    // uniform. Use moderate temperature so we get a meaningful but not
117	    // trivial target distribution. logits=[1,2,3] → softmax target.
118	    let logits = vec![1.0_f64, 2.0, 3.0];
119	    let temperature = 2.0_f64;
120	    let scaled: Vec<f64> = logits.iter().map(|x| x / temperature).collect();
121	    let m = scaled.iter().copied().fold(f64::NEG_INFINITY, f64::max);
122	    let exps: Vec<f64> = scaled.iter().map(|x| (x - m).exp()).collect();
123	    let z: f64 = exps.iter().sum();
124	    let p: Vec<f64> = exps.iter().map(|e| e / z).collect();
125	
126	    let n: usize = 10000;
127	    let mut counts = vec![0u64; logits.len()];
128	    for s in 0..n {
129	        let r = call_builtin(
130	            "sample",
131	            vec![vec1(&logits), scalar(temperature), scalar(s as f64)],
132	        )
133	        .unwrap();
134	        let id = r.data()[0] as usize;
135	        assert!(id < logits.len());
136	        counts[id] += 1;
137	    }
138	    // Pearson chi-square goodness-of-fit. With 3 categories => df=2.
139	    // Critical value at p=0.001 is ~13.82. Use a generous bound.
140	    let mut chi2 = 0.0_f64;
141	    for (c, pi) in counts.iter().zip(p.iter()) {
142	        let expected = (n as f64) * pi;
143	        let diff = *c as f64 - expected;
144	        chi2 += diff * diff / expected;
145	    }
146	    assert!(
147	        chi2 < 13.82,
148	        "chi2={chi2} counts={counts:?} expected_p={p:?}"
149	    );
150	}
