29	/// token). Otherwise the sampling distribution is `softmax(logits /
30	/// temperature)`, drawn via inverse-CDF on a single `Xorshift64`
31	/// uniform. `-inf` logits (the masked entries left by `top_k`) are
32	/// supported because the max-subtraction step makes them go to zero
33	/// after `exp`. The same `(logits, temperature, seed)` always yields
34	/// the same id.
35	fn builtin_sample(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
36	    if args.len() != 3 {
37	        return Err(RuntimeError::ArityMismatch {
38	            func: name.into(),
39	            expected: 3,
40	            got: args.len(),
41	        });
42	    }
43	    if args[0].rank() != 1 {
44	        return Err(RuntimeError::InvalidArgument {
45	            func: name.into(),
46	            reason: format!("logits must be a vector, got rank {}", args[0].rank()),
47	        });
48	    }
49	    if args[1].rank() != 0 {
50	        return Err(RuntimeError::InvalidArgument {
51	            func: name.into(),
52	            reason: "temperature must be a scalar".into(),
53	        });
54	    }
55	    if args[2].rank() != 0 {
56	        return Err(RuntimeError::InvalidArgument {
57	            func: name.into(),
58	            reason: "seed must be a scalar".into(),
59	        });
60	    }
61	    let logits = args[0].data();
62	    let temperature = args[1].data()[0];
63	    if temperature < 0.0 {
64	        return Err(RuntimeError::InvalidArgument {
65	            func: name.into(),
66	            reason: format!("temperature must be non-negative, got {temperature}"),
67	        });
68	    }
69	    if logits.is_empty() {
70	        return Err(RuntimeError::InvalidArgument {
71	            func: name.into(),
72	            reason: "logits must be non-empty".into(),
73	        });
74	    }
75	    if temperature == 0.0 {
76	        let mut best = 0usize;
77	        let mut bv = logits[0];
78	        for (i, &v) in logits.iter().enumerate().skip(1) {
79	            if v > bv {
80	                bv = v;
81	                best = i;
82	            }
83	        }
84	        return Ok(DenseArray::from_scalar(best as f64));
85	    }
86	    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
87	    let exps: Vec<f64> = logits
88	        .iter()
89	        .map(|x| ((x - m) / temperature).exp())
90	        .collect();
91	    let z: f64 = exps.iter().sum();
92	    // SplitMix64-style avalanche on the raw seed: xorshift64 mixes
93	    // poorly across small adjacent seeds (1, 2, 3...) when only one
94	    // draw is taken, which would bias single-shot sampling toward the
95	    // same bucket. Mixing first decorrelates seed→draw.
96	    let raw = args[2].data()[0] as i64 as u64;
97	    let mut z64 = raw.wrapping_add(0x9E3779B97F4A7C15);
98	    z64 = (z64 ^ (z64 >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
99	    z64 = (z64 ^ (z64 >> 27)).wrapping_mul(0x94D049BB133111EB);
100	    z64 ^= z64 >> 31;
101	    let mut rng = Xorshift64::new(z64);
102	    let u = rng.next_f64() * z;
103	    let mut acc = 0.0_f64;
104	    let mut idx = exps.len() - 1;
105	    for (i, &e) in exps.iter().enumerate() {
106	        acc += e;
107	        if u < acc {
108	            idx = i;
109	            break;
110	        }
