    // poorly across small adjacent seeds (1, 2, 3...) when only one
    // draw is taken, which would bias single-shot sampling toward the
    // same bucket. Mixing first decorrelates seed→draw.
    let raw = args[2].data()[0] as i64 as u64;
    let mut z64 = raw.wrapping_add(0x9E3779B97F4A7C15);
    z64 = (z64 ^ (z64 >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
