    let raw = args[2].data()[0] as i64 as u64;
    let mut z64 = raw.wrapping_add(0x9E3779B97F4A7C15);
    z64 = (z64 ^ (z64 >> 30)).wrapping_mul(0xBF58476D1CE4E5B9);
    z64 = (z64 ^ (z64 >> 27)).wrapping_mul(0x94D049BB133111EB);
    z64 ^= z64 >> 31;
    let mut rng = Xorshift64::new(z64);
    let u = rng.next_f64() * z;
    let mut acc = 0.0_f64;
    let mut idx = exps.len() - 1;
    for (i, &e) in exps.iter().enumerate() {
        acc += e;
        if u < acc {
            idx = i;
            break;
        }
    }
